SELECT ISNULL(njts, 0) as njts
FROM (SELECT njts
      FROM V_DXNJ
      WHERE GPH = #{workCard}
        AND ND = YEAR (getdate())) a RIGHT JOIN (SELECT 0 AS aa) B
ON 1=1;

SELECT TOP 1 rq
FROM v_kq_date_line
WHERE rq > #{rEndTime}
ORDER BY rq DESC;

SELECT TOP 1 rq
FROM v_kq_date_line
WHERE rq < #{startTime}
ORDER BY rq DESC;

